import statistics

def aggregate_by_region(rows):
    """Aggregates total, mean, median count of amounts per region."""
    by_region = {}
    for row in rows:
        r = row["region"]
        if r not in by_region:
            by_region[r] = []
        by_region[r].append(row["amount"])

    region_stats = {}
    for region, amounts in by_region.items():
        # Calculate stats only if there are records to avoid errors
        total = sum(amounts)
        count = len(amounts)
        mean = statistics.mean(amounts) if count > 0 else 0.0
        median = statistics.median(amounts) if count > 0 else 0.0

        region_stats[region] = {
            "total": total,
            "mean": mean,
            "median": median,
            "count": count,
        }
    return region_stats

def top_products(rows, n=5):
    """Finds the top N products by total sales amount."""
    by_product = {}
    for row in rows:
        p = row["product"]
        by_product[p] = by_product.get(p, 0) + row["amount"]

    # Sort and get top n
    top_list = sorted(by_product.items(), key=lambda x: x[1], reverse=True)[:n]
    return [{"product": p, "total": t} for p, t in top_list]

